const TABLE_W = 9360; // 6.5in in DXA

const NAVY = "1E3A8A", INK = "0F172A", MUTED = "475569";
const RULE = "D7DFEC", HEADBG = "EEF3FB", ALTBG = "F7F9FC";

let figureCounter = 0;
let tableCounter = 0;

/** Read intrinsic PNG dimensions from the IHDR chunk. */
function pngSize(file) {
  const buf = fs.readFileSync(file);
  return { width: buf.readUInt32BE(16), height: buf.readUInt32BE(20) };
}

function imageParagraph(file, maxWidth = CONTENT_PX) {
  const { width, height } = pngSize(file);
  const w = Math.min(maxWidth, width);
  const h = Math.round((height / width) * w);
  return new Paragraph({
    alignment: AlignmentType.CENTER,
    spacing: { before: 160, after: 60 },
    children: [
      new ImageRun({
        type: "png",
        data: fs.readFileSync(file),
        transformation: { width: w, height: h },
      }),
    ],
  });
}

function caption(text, kind = "Figure") {
  const n = kind === "Figure" ? ++figureCounter : ++tableCounter;
  return new Paragraph({
    alignment: AlignmentType.CENTER,
    spacing: { after: 240 },
    children: [
      new TextRun({ text: `${kind} ${n}. `, bold: true, size: 17, color: NAVY }),
      new TextRun({ text, size: 17, italics: true, color: MUTED }),
    ],
  });
}

function figure(file, text, maxWidth) {
  return [imageParagraph(file, maxWidth), caption(text, "Figure")];
}

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 360, after: 180 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 8, color: NAVY, space: 6 } },
    children: [new TextRun({ text, bold: true, size: 30, color: NAVY })],
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 280, after: 140 },
    children: [new TextRun({ text, bold: true, size: 25, color: INK })],
  });
}

function h3(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_3,
    spacing: { before: 220, after: 110 },
    children: [new TextRun({ text, bold: true, size: 22, color: MUTED })],
  });
}

/** Body paragraph. Accepts a string, or an array of {t, b, i, code} runs. */
function p(content, opts = {}) {
  const runs = (typeof content === "string" ? [{ t: content }] : content).map(
    (r) =>
      new TextRun({
        text: r.t,
        bold: !!r.b,
        italics: !!r.i,
        size: 21,
        color: r.color || INK,
        font: r.code ? "Consolas" : undefined,
      })
  );
  return new Paragraph({
    spacing: { after: opts.after ?? 140, line: 300 },
    alignment: opts.align || AlignmentType.LEFT,
    children: runs,
  });
}

function bullet(content, level = 0) {
  const runs = (typeof content === "string" ? [{ t: content }] : content).map(
    (r) =>
      new TextRun({
        text: r.t, bold: !!r.b, italics: !!r.i, size: 21,
        color: r.color || INK, font: r.code ? "Consolas" : undefined,
      })
  );
  return new Paragraph({
    numbering: { reference: "bullets", level },
    spacing: { after: 70, line: 290 },
    children: runs,
  });
}

function numbered(content, level = 0) {
  const runs = (typeof content === "string" ? [{ t: content }] : content).map(
    (r) => new TextRun({ text: r.t, bold: !!r.b, italics: !!r.i, size: 21,
                         color: r.color || INK, font: r.code ? "Consolas" : undefined })
  );
  return new Paragraph({
    numbering: { reference: "numbers", level },
    spacing: { after: 70, line: 290 },
    children: runs,
  });
}

function code(lines) {
  return new Paragraph({
    spacing: { before: 120, after: 160 },
    shading: { type: ShadingType.CLEAR, fill: "F4F6FA" },
    border: {
      left: { style: BorderStyle.SINGLE, size: 12, color: NAVY, space: 8 },
      top: { style: BorderStyle.SINGLE, size: 2, color: RULE, space: 4 },
      bottom: { style: BorderStyle.SINGLE, size: 2, color: RULE, space: 4 },
      right: { style: BorderStyle.SINGLE, size: 2, color: RULE, space: 4 },
    },
    children: lines.flatMap((line, i) => [
      ...(i ? [new TextRun({ break: 1 })] : []),
      new TextRun({ text: line, font: "Consolas", size: 17, color: INK }),
    ]),
  });
}

function callout(title, body, accent = "B45309") {
  return new Paragraph({
    spacing: { before: 160, after: 200, line: 290 },
    shading: { type: ShadingType.CLEAR, fill: "FBF7EF" },
    border: {
      left: { style: BorderStyle.SINGLE, size: 18, color: accent, space: 10 },
      top: { style: BorderStyle.SINGLE, size: 2, color: RULE, space: 6 },
      bottom: { style: BorderStyle.SINGLE, size: 2, color: RULE, space: 6 },
      right: { style: BorderStyle.SINGLE, size: 2, color: RULE, space: 6 },
    },
    children: [
      new TextRun({ text: `${title} `, bold: true, size: 20, color: accent }),
      new TextRun({ text: body, size: 20, color: INK }),
    ],
  });
}

/** Table from a header row plus body rows. `align` is per-column: 'l' | 'r'. */
function table(header, rows, widths, align = null) {
  const total = widths.reduce((a, b) => a + b, 0);
  const cols = widths.map((w) => Math.round((w / total) * TABLE_W));
  const alignment = align || header.map(() => "l");

  const cell = (text, i, isHeader, zebra) =>
    new TableCell({
      width: { size: cols[i], type: WidthType.DXA },
      shading: { type: ShadingType.CLEAR, fill: isHeader ? HEADBG : zebra ? ALTBG : "FFFFFF" },
      margins: { top: 70, bottom: 70, left: 90, right: 90 },
      verticalAlign: VerticalAlign.CENTER,
      children: [
        new Paragraph({
          alignment: alignment[i] === "r" ? AlignmentType.RIGHT : AlignmentType.LEFT,
          spacing: { after: 0, line: 260 },
          children: String(text).split("\n").flatMap((part, k) => [
            ...(k ? [new TextRun({ break: 1 })] : []),
            new TextRun({
              text: part, bold: isHeader, size: 18,
              color: isHeader ? NAVY : INK,
            }),
          ]),
        }),
      ],
    });

  return new Table({
    width: { size: TABLE_W, type: WidthType.DXA },
    columnWidths: cols,
    rows: [
      new TableRow({
        tableHeader: true,
        children: header.map((t, i) => cell(t, i, true, false)),
      }),
      ...rows.map((r, ri) =>
        new TableRow({ children: r.map((t, i) => cell(t, i, false, ri % 2 === 1)) })
      ),
    ],
  });
}

function spacer(after = 160) {
  return new Paragraph({ spacing: { after }, children: [] });
}

function pageBreak() {
  return new Paragraph({ children: [new PageBreak()] });
}

